import React, {useState} from 'react';

const Hobbies = () => {
    const [isShown, SetShown] = useState({first:false,second:false,third:false});

    return(
        <div>
            <h2 className="ui header">Favorite Activities</h2>
            <div className="ui center red segment"
                 onMouseEnter={() => SetShown({first:true,second:false,third:false})}
                 onMouseLeave={() => SetShown({first:false,second:false,third:false})}
            >
                <h3><i className="heartbeat icon"></i>Gym</h3>
                {isShown.first && (
                    <div className="ui center"><p>Avid Gym goer. Les Mills member since 2 0 1 8! :)</p></div>
                )}
            </div>
            <div className="ui center purple segment"
                 onMouseEnter={() => SetShown({first:false,second:true,third:false})}
                 onMouseLeave={() => SetShown({first:false,second:false,third:false})}
            >
                <h3><i className="music icon"></i>Piano</h3>
                {isShown.second && (
                    <div className="ui center"><p>I've played for about a year now :) This is what got me into audio programming</p></div>
                )}
            </div>
            <div className="ui center blue segment"
                 onMouseEnter={() => SetShown({first:false,second:false,third:true})}
                 onMouseLeave={() => SetShown({first:false,second:false,third:false})}
            >
                <h3><img src={require('../resources/swimming.png')} style={{width:"1.5em",paddingRight:"0.3em",height:"1em"}}/>Swimming</h3>
                {isShown.third && (
                    <div className="ui center"><p>Avid Gym goer. Les Mills member since 2 0 1 8! :)</p></div>
                )}
            </div>
        </div>
    )
};

export default Hobbies;
